    for (const prop of node.props) {
      // same-name shorthand - :arg is expanded to :arg="arg"
      // in-DOM templates will be parsed into :arg="" by the browser
      if (
        prop.type === NodeTypes.DIRECTIVE &&
        prop.name === 'bind' &&
        prop.arg &&
        prop.arg.type === NodeTypes.SIMPLE_EXPRESSION &&
        prop.arg.isStatic &&
        !prop.exp
      ) {
        const arg = prop.arg
        const propName = camelize(arg.content)
        if (
          validFirstIdentCharRE.test(propName[0]) ||
          // allow hyphen first char for https://github.com/vuejs/language-tools/pull/3424
          propName[0] === '-'
        ) {
          prop.exp = createSimpleExpression(propName, false, arg.loc)
        } else {
          context.onError(
            createCompilerError(
              ErrorCodes.X_V_BIND_INVALID_SAME_NAME_ARGUMENT,
              arg.loc,
            ),
          )
          prop.exp = createSimpleExpression('', true, arg.loc)
        }
      } else if (
        prop.type === NodeTypes.DIRECTIVE &&
        prop.name === 'bind' &&
        prop.arg &&
        prop.arg.type === NodeTypes.SIMPLE_EXPRESSION &&
        prop.arg.isStatic &&
        prop.exp &&
        prop.exp.type === NodeTypes.SIMPLE_EXPRESSION &&
        !prop.exp.content.trim() &&
        prop.loc.source.endsWith(`=""`) === false
      ) {
        const arg = prop.arg
        const propName = camelize(arg.content)
        if (
          validFirstIdentCharRE.test(propName[0]) ||
          // allow hyphen first char for https://github.com/vuejs/language-tools/pull/3424
          propName[0] === '-'
        ) {
          prop.exp.content = propName
        } else {
          context.onError(
            createCompilerError(
              ErrorCodes.X_V_BIND_INVALID_SAME_NAME_ARGUMENT,
              arg.loc,
            ),
          )
          prop.exp.content = ''
        }
      }
    }
  }
}

