import { camelize } from '@vue/shared'
import {
  NodeTypes,
  type SimpleExpressionNode,
  createSimpleExpression,
} from '../ast'
import type { NodeTransform } from '../transform'
import { ErrorCodes, createCompilerError } from '../errors'
import { validFirstIdentCharRE } from '../utils'

export const transformVBindShorthand: NodeTransform = (node, context) => {
  if (node.type === NodeTypes.ELEMENT) {
    for (const prop of node.props) {
      // same-name shorthand - :arg is expanded to :arg="arg"
      // in-DOM templates will be parsed into :arg="" by the browser
      if (
        prop.type === NodeTypes.DIRECTIVE &&
        prop.name === 'bind' &&
        (!prop.exp || (prop.exp.type === NodeTypes.SIMPLE_EXPRESSION && !prop.exp.content.trim() && __BROWSER__))
      ) {
        const arg = prop.arg
        if (!arg || arg.type !== NodeTypes.SIMPLE_EXPRESSION || !arg.isStatic) {
          // invalid arg!
          if (!prop.exp) {
            context.onError(
              createCompilerError(
                ErrorCodes.X_V_BIND_INVALID_SAME_NAME_ARGUMENT,
                arg?.loc || prop.loc,
              ),
            )
            prop.exp = createSimpleExpression('', true, arg?.loc || prop.loc)
          }
          continue
        }

        const propName = camelize(arg.content)
        if (
          validFirstIdentCharRE.test(propName[0]) ||
          // allow hyphen first char for https://github.com/vuejs/language-tools/pull/3424
          propName[0] === '-'
        ) {
          prop.exp = createSimpleExpression(propName, false, arg.loc)
        } else if (!prop.exp) {
          context.onError(
            createCompilerError(
              ErrorCodes.X_V_BIND_INVALID_SAME_NAME_ARGUMENT,
              arg.loc,
            ),
          )
          prop.exp = createSimpleExpression('', true, arg.loc)
        } else if (prop.exp) {
          // If we reach here, it's __BROWSER__ and we have an invalid name for same-name shorthand.
          // In Vue 3.4+ an empty `v-bind` in browser is treated as same-name shorthand, unless name invalid.
          // Wait, if name is invalid, and it's in-DOM, what should it be?
          // It should be treated as empty expression -> empty string binding. But since it's `v-bind`,
          // `prop.exp` needs an expression node, we can leave `prop.exp.content = ""`
          prop.exp.content = ''
        }
      }
    }
  }
