            // only simple expression is allowed for same-name shorthand
            context.onError(
              createCompilerError(
                ErrorCodes.X_V_BIND_INVALID_SAME_NAME_ARGUMENT,
                prop.arg.loc || prop.loc,
              ),
            )
            prop.exp = createSimpleExpression('', true, prop.arg.loc || prop.loc)
