      key: {
        content: `id`,
        isStatic: true,
        loc: {
          start: {
            line: 1,
            column: 13,
          },
          end: {
            line: 1,
            column: 15,
          },
        },
      },
      value: {
        content: `id`,
        isStatic: false,
        loc: {
          start: {
